# ---------------------------------------------------------------------------
# Data loading (cached)
# ---------------------------------------------------------------------------

# NOT cached — globbing the directory is cheap, and we need it to
# return fresh paths so the load() cache invalidates when a new CSV
# arrives.
def _latest_file(prefix: str) -> Optional[Path]:
    """Return the most recent CSV file in output/ with the given prefix."""
    return catalog_latest_file(prefix, OUTPUT_DIR)


@st.cache_data(persist="disk", show_spinner="Loading data…")
def _read_csv_cached(path_str: str, mtime: float) -> pd.DataFrame:
    """Disk-persisted CSV reader. Cache key = (path, mtime), so a new
    CSV with a different mtime invalidates automatically — even though
    the persistent cache has no TTL."""
    try:
        return pd.read_csv(path_str, low_memory=False)
    except Exception as exc:  # noqa: BLE001
        st.warning(f"Could not read {Path(path_str).name}: {exc}")
        return pd.DataFrame()


def load(prefix: str) -> pd.DataFrame:
    """Find the latest CSV for this prefix and return it (cached)."""
    p = _latest_file(prefix)
    if p is None:
        return pd.DataFrame()
    return _read_csv_cached(str(p), p.stat().st_mtime)


def _read_csv_lean(path: Path,
                   usecols: list[str],
                   numeric_cols: tuple[str, ...] = ()) -> pd.DataFrame:
    """Read only the CSV columns the app actually consumes.

    The rolling CIN7 exports keep gaining fields. Loading every column
    across multi-year sale/purchase snapshots pushes Render's memory limit
    during Streamlit reruns, so the big merged loaders use this helper.
    """
    try:
        header = pd.read_csv(path, nrows=0).columns.tolist()
        cols = [c for c in usecols if c in header]
        if not cols:
            return pd.DataFrame()
        df = pd.read_csv(path, usecols=cols, low_memory=False)
    except Exception:
        return pd.DataFrame()
    for col in numeric_cols:
        if col in df.columns:
            df[col] = pd.to_numeric(
                df[col], errors="coerce", downcast="float")
    return df


def _ensure_columns(df: pd.DataFrame,
                    columns: list[str]) -> pd.DataFrame:
    for col in columns:
        if col not in df.columns:
            df[col] = pd.NA
    return df


def file_mtime(prefix: str) -> Optional[datetime]:
    return catalog_file_mtime(prefix, OUTPUT_DIR)


def _fmt_number(n) -> str:
    if pd.isna(n):
        return "—"
    if abs(n) >= 1_000_000:
        return f"{n/1_000_000:,.2f}M"
    if abs(n) >= 1_000:
        return f"{n/1_000:,.1f}k"
    return f"{n:,.0f}"


def _fmt_money(n) -> str:
    if pd.isna(n) or n is None:
        return "—"
    return f"${n:,.0f}"


def _to_num(series: pd.Series) -> pd.Series:
    return pd.to_numeric(series, errors="coerce")


_BAD_SALE_STATUSES = ("VOIDED", "CREDITED", "CANCELLED", "CANCELED")
_SALES_ACTUAL_AMOUNT_COLS = (
    "InvoiceAmount",
    "GrandTotal",
    "Total",
    "InvoiceTotal",
)


def _sales_actuals_frame(
        sales_full_df: Optional[pd.DataFrame],
        sales_headers_df: Optional[pd.DataFrame],
        sale_lines_df: Optional[pd.DataFrame] = None,
) -> tuple[pd.DataFrame, str, str]:
    """Return valid CIN7 sales headers for cashflow actuals.

    Cashflow actual sales are grouped by InvoiceDate, not OrderDate.
    The amount is CIN7 Revenue basis, not gross InvoiceAmount:
    InvoiceAmount minus tax, excluding voided/credited/cancelled
    sales. That matches the General Dashboard Revenue tile.
    """
    line_tax_by_sale: dict[str, float] = {}
    if (sale_lines_df is not None and not sale_lines_df.empty
            and "SaleID" in sale_lines_df.columns
            and "Tax" in sale_lines_df.columns):
        try:
            _sl = sale_lines_df[["SaleID", "Tax"]].copy()
            _sl["SaleID"] = _sl["SaleID"].astype(str)
            _sl["Tax"] = _to_num(_sl["Tax"]).fillna(0.0)
            line_tax_by_sale = _sl.groupby("SaleID")["Tax"].sum().to_dict()
        except Exception:  # noqa: BLE001
            line_tax_by_sale = {}

    candidates = (
        ("merged sales history", sales_full_df),
        ("sales headers", sales_headers_df),
    )
    for source_name, df in candidates:
        if df is None or df.empty:
            continue
        if "InvoiceDate" not in df.columns:
            continue
        amt_col = next(
            (c for c in _SALES_ACTUAL_AMOUNT_COLS if c in df.columns),
            None,
        )
        if not amt_col:
            continue
        out = df.copy()
        out["__sales_date"] = pd.to_datetime(
            out["InvoiceDate"], errors="coerce", utc=True
        ).dt.tz_localize(None)
        out["__gross_sales_amount"] = _to_num(out[amt_col]).fillna(0.0)
        if "Tax" in out.columns:
            tax = _to_num(out["Tax"]).fillna(0.0)
        else:
            tax = pd.Series(0.0, index=out.index)
        if line_tax_by_sale and "SaleID" in out.columns:
            line_tax = out["SaleID"].astype(str).map(
                line_tax_by_sale).fillna(0.0)
            tax = tax.where(tax != 0, line_tax)
        if amt_col == "Total":
            # Header Total is already the closest revenue fallback.
            out["__sales_amount"] = out["__gross_sales_amount"]
            amount_label = "Total"
        else:
            out["__sales_amount"] = (
                out["__gross_sales_amount"] - tax)
            amount_label = f"{amt_col} - Tax"
        out = out.dropna(subset=["__sales_date"])
        if "Status" in out.columns:
            out = out[
                ~out["Status"].astype(str).str.upper().isin(
                    _BAD_SALE_STATUSES)
            ]
        return out, source_name, amount_label
    return pd.DataFrame(), "", ""


def _weekly_actual_sales_amounts(
        sales_full_df: Optional[pd.DataFrame],
        sales_headers_df: Optional[pd.DataFrame],
        sale_lines_df: Optional[pd.DataFrame] = None,
) -> tuple[dict[str, float], str, str]:
    actuals, source_name, amt_col = _sales_actuals_frame(
        sales_full_df, sales_headers_df, sale_lines_df)
    if actuals.empty:
        return {}, source_name, amt_col
    wk = actuals["__sales_date"].dt.normalize() - pd.to_timedelta(
        actuals["__sales_date"].dt.weekday, unit="D")
    tmp = pd.DataFrame({
        "week_start": wk.dt.strftime("%Y-%m-%d"),
        "amount": actuals["__sales_amount"],
    })
    weekly = tmp.groupby("week_start")["amount"].sum().to_dict()
    return {str(k): float(v) for k, v in weekly.items()}, source_name, amt_col


def _sales_actuals_in_window(
        actuals: pd.DataFrame,
        start,
        end_exclusive,
) -> tuple[float, int]:
    if actuals is None or actuals.empty:
        return 0.0, 0
    start_ts = pd.Timestamp(start).normalize()
    end_ts = pd.Timestamp(end_exclusive).normalize()
    mask = (
        (actuals["__sales_date"] >= start_ts)
        & (actuals["__sales_date"] < end_ts)
    )
    win = actuals.loc[mask]
    if win.empty:
        return 0.0, 0
    amount = float(win["__sales_amount"].sum())
    order_col = next(
        (c for c in ("SaleID", "SaleNumber", "OrderNumber",
                     "InvoiceNumber") if c in win.columns),
        None,
    )
    count = int(win[order_col].astype(str).nunique()) if order_col else len(win)
    return amount, count


def _sales_week_label(start_ts) -> str:
    start = pd.Timestamp(start_ts).normalize()
    end = start + pd.Timedelta(days=6)
    return f"{start.strftime('%b')} {start.day} - {end.strftime('%b')} {end.day}"


def _safe_cache_clear() -> None:
    """v2.67.210 — race-safe wrapper for Streamlit's cache_data
    clear.

    Streamlit's cache_data clear does a shutil.rmtree on the
    on-disk cache directory (/opt/render/.streamlit/cache). The
    background warm_engine.py process — kicked off by sync_loop
    after every sync — writes @st.cache_data entries into that
    SAME directory. If a clear and a warm-engine write
    interleave, rmtree hits a freshly-created file mid-walk and
    raises `OSError [Errno 39] Directory not empty`, which (un-
    wrapped) crashes the whole Streamlit page.

    The clear is best-effort: a missed clear just means the next
    render recomputes a few cache entries. So we retry once
    (the racing writer usually finishes within a few hundred ms)
    then swallow the error. Never fatal.

    Every callsite app-wide routes through this helper; the raw
    Streamlit call is bound via getattr below so it appears
    nowhere as a literal — that's deliberate, so the blanket
    find/replace that introduced this helper couldn't recurse
    into it."""
    import time as _t
    _clear = getattr(st.cache_data, "clear")
    for _attempt in range(2):
        try:
            _clear()
            return
        except OSError:
            if _attempt == 0:
                _t.sleep(0.4)
                continue
            # Second failure — give up quietly. Stale cache is
            # harmless; crashing the page is not.
            return
        except Exception:  # noqa: BLE001
            # Any other cache-clear failure is also non-fatal.
            return


def _to_date(series: pd.Series) -> pd.Series:
    return pd.to_datetime(series, errors="coerce", utc=True)


def _analysis_today_from_dates(*date_series: pd.Series) -> pd.Timestamp:
    """Anchor rolling sales windows to the newest date in the snapshot.

    Render may serve a last-good engine_output.csv while a fresh sync or
    ABC rebuild is still catching up. Using wall-clock today for recent
    windows can then make 45d demand look like zero even though the
    snapshot itself has recent sales relative to its own data date.
    """
    wall_today = pd.Timestamp(datetime.now().date())
    max_seen = pd.NaT
    for series in date_series:
        if series is None:
            continue
        try:
            dates = pd.to_datetime(series, errors="coerce", utc=True)
        except Exception:  # noqa: BLE001
            continue
        if not isinstance(dates, pd.Series):
            dates = pd.Series(dates)
        dates = dates.dt.tz_localize(None).dropna()
        if dates.empty:
            continue
        candidate = dates.max()
        if pd.isna(max_seen) or candidate > max_seen:
            max_seen = candidate
    if pd.notna(max_seen):
        data_today = pd.Timestamp(max_seen).normalize()
        if data_today <= wall_today:
            return data_today
    return wall_today


def _compute_slow_mover_clearance(stock_df: pd.DataFrame,
                                    sale_lines_df: pd.DataFrame,
                                    products_df: pd.DataFrame,
                                    dormancy_warnings: dict,
                                    period_start,
                                    period_end) -> dict:
    """v2.67.38 — compute "value of slow stock cleared" over a date
    window. Used by:
      - Overview KPI tile (this month)
      - Slow Movers page (this month / last 90d / etc)
      - Weekly email script (last 7 days)

    Definition: slow stock cleared = sum of (Quantity × cost) on
    sale_lines for any SKU that has an active dormancy warning,
    invoiced within [period_start, period_end].

    Returns:
      sku_count        — how many distinct slow SKUs sold in window
      units_sold       — total units cleared
      revenue          — sum(Total) on those sale lines
      cost_value       — sum(Quantity × AverageCost) — the cost
                          basis we cleared off the shelves; this is
                          what relieves stock-holding cash
      ai_attributed    — TODO. Reserved for when we wire a signal
                          source distinguishing AI-driven sales.
                          Currently None to make absence visible.

    Notes on attribution: salespeople using the AI Assistant to
    surface slow movers can't yet be cleanly tracked back to the
    line items they sold. v2.67.39+ should add a signal — perhaps
    tagging sales whose product was in a recent ai_audit_logs query
    where the user clicked through, or per-rep attribution."""
    if (sale_lines_df is None or sale_lines_df.empty
            or "InvoiceDate" not in sale_lines_df.columns
            or "SKU" not in sale_lines_df.columns):
        return {
            "sku_count": 0, "units_sold": 0.0,
            "revenue": 0.0, "cost_value": 0.0,
            "ai_attributed": None,
        }
    if not dormancy_warnings:
        return {
            "sku_count": 0, "units_sold": 0.0,
            "revenue": 0.0, "cost_value": 0.0,
            "ai_attributed": None,
        }
    slow_skus = set(dormancy_warnings.keys())
    sl = sale_lines_df.copy()
    sl["InvoiceDate"] = pd.to_datetime(sl["InvoiceDate"], errors="coerce")
    sl["SKU"] = sl["SKU"].astype(str)
    in_window = sl[
        (sl["SKU"].isin(slow_skus))
        & (sl["InvoiceDate"] >= pd.Timestamp(period_start))
        & (sl["InvoiceDate"] <= pd.Timestamp(period_end))
    ]
    # Status filter — VOIDED/CREDITED/CANCELLED don't count as cleared.
    if "Status" in in_window.columns:
        bad = ("VOIDED", "CREDITED", "CANCELLED", "CANCELED")
        in_window = in_window[
            ~in_window["Status"].astype(str).str.upper().isin(bad)]
    if in_window.empty:
        return {
            "sku_count": 0, "units_sold": 0.0,
            "revenue": 0.0, "cost_value": 0.0,
            "ai_attributed": None,
        }
    qty = _to_num(in_window["Quantity"]).fillna(0)
    rev = (_to_num(in_window["Total"]).fillna(0)
            if "Total" in in_window.columns
            else pd.Series(0.0, index=in_window.index))
    # Cost basis: prefer line-level AverageCost; fall back to product
    # master AverageCost.
    if "AverageCost" in in_window.columns:
        line_cost = _to_num(in_window["AverageCost"]).fillna(0)
    else:
        line_cost = pd.Series(0.0, index=in_window.index)
    if products_df is not None and not products_df.empty:
        p_cost_map = (products_df.set_index("SKU")["AverageCost"]
                       .apply(lambda v: float(v or 0))
                       .to_dict()) if "AverageCost" in products_df.columns else {}
        # Where line cost is 0 fall back to product master.
        line_cost = line_cost.where(
            line_cost > 0,
            in_window["SKU"].map(lambda s: float(p_cost_map.get(s, 0))).fillna(0))
    cost_value = float((qty * line_cost).sum())
    return {
        "sku_count": int(in_window["SKU"].nunique()),
        "units_sold": float(qty.sum()),
        "revenue": float(rev.sum()),
        "cost_value": cost_value,
        "ai_attributed": None,  # placeholder for v2.67.39+
    }


def _headline_stock_value(stock_df: pd.DataFrame,
                            products_df: Optional[pd.DataFrame] = None
                            ) -> float:
    """v2.67.37 — single source of truth for the "Current stock value"
    headline number. Used by Overview, Ordering, AND Monthly Metrics
    so they all show exactly the same dollar amount. James works
    sales-team commissions off the Monthly Metrics report, so this
    HAS to tie out to the cent.

    Calculation: sum CIN7's `StockOnHand` field across all SKU/
    location rows. CIN7 already publishes a FIFO-based dollar value
    in this field (matches CIN7's Product Availability totals). No
    AverageCost fallback for missing values — those genuinely have
    no cost basis in CIN7 and including a fabricated value would
    inflate the headline above what CIN7 itself reports.

    Fallback path: if `StockOnHand` is missing entirely (very old
    syncs predating the field), compute `OnHand × AverageCost` —
    same legacy fallback Overview and Monthly Metrics already use.

    Per-SKU optimum/excess calculations on the Ordering page still
    use a richer per-SKU cost chain (engine_df["OnHandValue"], with
    family/category-median fallbacks for missing costs). That chain
    is necessary for sensible math when CIN7 hasn't computed FIFO
    for some SKUs, but it's NOT what we publish as the headline."""
    if stock_df is None or stock_df.empty:
        return 0.0
    if "StockOnHand" in stock_df.columns:
        return float(_to_num(stock_df["StockOnHand"]).fillna(0).sum())
    # Legacy fallback — same as Overview's existing behaviour.
    if products_df is None or products_df.empty:
        return 0.0
    if "OnHand" not in stock_df.columns:
        return 0.0
    p_cost = products_df.set_index("SKU")["AverageCost"].to_dict()
    on_hand = _to_num(stock_df["OnHand"]).fillna(0)
    skus_stk = stock_df["SKU"].astype(str)
    return float(sum(
        on_hand.iloc[i] * float(p_cost.get(skus_stk.iloc[i], 0) or 0)
        for i in range(len(stock_df))
    ))


def _compute_slow_stock_holding(engine_df: pd.DataFrame,
                                  dormancy_warnings: dict) -> dict:
    """v2.67.53 — single source of truth for "slow-stock value on
    shelf". Used by:
      - Overview's "Slow stock — value on shelf" tile
      - Slow Movers page's "Stock value tied up" tile
      - The engine's monthly snapshot writer (so MoM delta caption
        is comparable)

    Why this had to be unified: the user reported a $58k discrepancy
    between Overview ($290,872) and the Slow Movers page ($232,153)
    for what's labelled the same metric. Three different code paths
    were computing it three different ways:
      - Overview: ALL flagged SKUs × raw stock.StockOnHand
                  (no parent filter, no OnHand>0 filter)
      - Slow Movers page: parents+OnHand>0 × engine_df.OnHandValue
      - Snapshot writer: parents+OnHand>0 × stock.StockOnHand

    The actionable definition (what the buyer can actually clear)
    is parents/standalones with OnHand>0. Children's stock rolls up
    to the master, so counting them double-counts; zero-stock entries
    aren't holdings. And engine_df.OnHandValue is the canonical cost
    chain (handles missing CIN7 FIFO via family/category medians) —
    it's what the Ordering page's excess-value math uses everywhere
    else, so picking it here keeps that chain consistent.

    Returns: {sku_count, units_held, value_held, filter_summary}.
    Defensive: every column access is conditional so a leaner
    engine_df shape doesn't blow up (e.g. v2.67.32 lifted the engine
    to module scope and earlier callers built minimal frames)."""
    if (engine_df is None or engine_df.empty
            or not dormancy_warnings):
        return {
            "sku_count": 0,
            "units_held": 0.0,
            "value_held": 0.0,
            "filter_summary": "no flagged SKUs / no engine_df",
        }
    slow_set = set(str(k) for k in dormancy_warnings.keys())
    df = engine_df.copy()
    if "SKU" not in df.columns:
        return {"sku_count": 0, "units_held": 0.0, "value_held": 0.0,
                "filter_summary": "engine_df missing SKU column"}
    df = df[df["SKU"].astype(str).isin(slow_set)]
    # OnHand > 0 only — nothing to clear if it's already gone.
    if "OnHand" in df.columns:
        df = df[_to_num(df["OnHand"]).fillna(0) > 0]
    # v2.67.183 — drop CHILDREN that have NO direct OnHand. Their
    # availability comes from BOM-deconstructing the parent, so
    # counting their derived value here would double-count.
    # KEEP children with OnHand>0 — that's stock someone booked
    # directly against the child SKU (e.g. profile cut, end-cap
    # pack). CIN7 fulfils child orders from direct child OnHand
    # FIRST, then falls back to BOM deconstruction — so direct
    # child stock is real, separate inventory with real value
    # that belongs in the holding total.
    #
    # Previously: dropped ALL is_non_master_tube rows. That
    # silently excluded directly-booked child stock from the
    # slow-stock total, under-reporting tied-up capital.
    if "is_non_master_tube" in df.columns:
        non_master = df["is_non_master_tube"].fillna(False).astype(bool)
        on_hand_n = (_to_num(df["OnHand"]).fillna(0)
                          if "OnHand" in df.columns
                          else pd.Series(0, index=df.index))
        # Drop only the non-masters WITHOUT direct stock.
        df = df[~(non_master & (on_hand_n <= 0))]
    # If an old dormancy warning is still active but the current engine
    # row clearly has recent movement, do not let that stale warning
    # inflate the slow-stock holding value. The warning can still show in
    # Ordering until the normal recovery/lift process clears it; this
    # KPI should represent stock that is slow now.
    if "is_dormant" in df.columns:
        dormant_now = df["is_dormant"].fillna(False).astype(bool)
        recent_90d = (_to_num(df["effective_units_90d"]).fillna(0)
                      if "effective_units_90d" in df.columns
                      else pd.Series(0, index=df.index))
        recent_45d = (_to_num(df["units_45d"]).fillna(0)
                      if "units_45d" in df.columns
                      else pd.Series(0, index=df.index))
        recent_movement = (recent_90d > 0) | (recent_45d > 0)
        df = df[dormant_now | (~recent_movement)]
    units_held = (float(_to_num(df["OnHand"]).fillna(0).sum())
                   if "OnHand" in df.columns else 0.0)
    value_held = (float(_to_num(df["OnHandValue"]).fillna(0).sum())
                   if "OnHandValue" in df.columns else 0.0)
    detail_cols = [c for c in [
        "SKU", "Name", "ABC", "trend_flag", "OnHand", "Available",
        "OnOrder", "OnHandValue", "effective_units_12mo",
        "effective_units_90d", "units_45d", "last_6mo_series",
        "is_dormant", "is_non_master_tube",
    ] if c in df.columns]
    detail_df = (
        df[detail_cols].copy()
        if detail_cols else pd.DataFrame()
    )
    if not detail_df.empty:
        detail_df["Dormancy first seen"] = (
            detail_df["SKU"].astype(str).map(
                lambda s: (dormancy_warnings.get(s) or {}).get(
                    "first_seen_dormant_at", "")))
        detail_df["Dormancy last seen"] = (
            detail_df["SKU"].astype(str).map(
                lambda s: (dormancy_warnings.get(s) or {}).get(
                    "last_seen_dormant_at", "")))
        detail_df = detail_df.sort_values(
            "OnHandValue", ascending=False, na_position="last")
    return {
        "sku_count": int(len(df)),
        "units_held": units_held,
        "value_held": value_held,
        "detail_df": detail_df,
        "filter_summary": "parents/standalones + children with "
                            "direct OnHand>0; engine OnHandValue "
                            "cost chain; excludes stale warnings when "
                            "current engine movement is positive",
    }


def rows_selector(label: str = "Rows to show", key: str = "rows",
                  default: int = 100) -> int:
    """Standard page-size selector. Returns row limit (large int for 'All')."""
    options = [10, 50, 100, 1000, "All"]
    index = options.index(default) if default in options else 2
    choice = st.selectbox(label, options, index=index, key=key)
    return 10**9 if choice == "All" else int(choice)


def _render_ordering_editor_enhancer(anchor_id: str) -> None:
    """Attach small browser-side niceties to the Ordering data editor."""
    import streamlit.components.v1 as _stc

    _anchor_js = json.dumps(anchor_id)
    _stc.html("""
<script>
(() => {
  const ANCHOR_ID = %s;
  const ENHANCER_VERSION = "persistent-row-pan-v2";
  let doc = null;
  try {
    doc = window.parent && window.parent.document;
  } catch (e) {
    return;
  }
  if (!doc) return;

  const STYLE_ID = "w4s-ordering-editor-enhancer-style";
  if (!doc.getElementById(STYLE_ID)) {
    const style = doc.createElement("style");
    style.id = STYLE_ID;
    style.textContent = `
      .w4s-ordering-editor-frame {
        outline: none;
      }
      .w4s-ordering-editor-frame.w4s-ordering-dragging,
      .w4s-ordering-editor-frame.w4s-ordering-dragging * {
        cursor: ew-resize !important;
        user-select: none !important;
      }
      .w4s-ordering-active-row {
        position: absolute;
        left: 0;
        right: 0;
        height: 40px;
        display: none;
        opacity: 0;
        pointer-events: none;
        z-index: 20;
        background: rgba(250, 204, 21, 0.16);
        border-top: 1px solid rgba(245, 158, 11, 0.45);
        border-bottom: 1px solid rgba(245, 158, 11, 0.45);
        box-shadow: inset 4px 0 0 rgba(217, 119, 6, 0.92);
        transition: opacity 0.18s ease;
      }
    `;
    doc.head.appendChild(style);
  }

  function isAfter(anchor, el) {
    return !!(anchor.compareDocumentPosition(el)
      & 4);
  }

  function findEditorFrame(anchor) {
    const selectors = [
      '[data-testid="stDataFrame"]',
      '[data-testid="stDataFrameResizable"]'
    ].join(",");
    return Array.from(doc.querySelectorAll(selectors))
      .find((el) => isAfter(anchor, el));
  }

  function widestScroller(root) {
    const candidates = Array.from(root.querySelectorAll("*"))
      .filter((el) => (el.scrollWidth - el.clientWidth) > 12);
    candidates.sort((a, b) =>
      (b.scrollWidth - b.clientWidth) - (a.scrollWidth - a.clientWidth));
    return candidates[0] || root;
  }

  function isEditableTarget(target) {
    const el = target && target.closest
      ? target.closest("input, textarea, select, button, [contenteditable='true']")
      : null;
    return !!el;
  }

  function install() {
    const anchor = doc.getElementById(ANCHOR_ID);
    if (!anchor) return false;
    const frame = findEditorFrame(anchor);
    if (!frame) return false;
    const installId = `${ANCHOR_ID}:${ENHANCER_VERSION}`;
    if (frame.dataset.w4sOrderingEnhancer === installId) return true;
    frame.dataset.w4sOrderingEnhancer = installId;
    frame.classList.add("w4s-ordering-editor-frame");
    frame.setAttribute("tabindex", "0");

    const host = frame;
    if (!host.style.position || host.style.position === "static") {
      host.style.position = "relative";
    }

    doc.querySelectorAll(".w4s-ordering-active-row").forEach((el) => {
      if (el.parentElement !== host) el.remove();
    });
    let guide = host.querySelector(":scope > .w4s-ordering-active-row");
    if (guide) guide.remove();
    guide = doc.createElement("div");
    guide.className = "w4s-ordering-active-row";
    host.appendChild(guide);

    function hideGuide() {
      guide.style.opacity = "0";
      setTimeout(() => {
        if (guide.style.opacity === "0") {
          guide.style.display = "none";
        }
      }, 220);
    }

    function showGuide(ev) {
      const hostRect = host.getBoundingClientRect();
      const header = 36;
      const rowHeight = 40;
      const y = ev.clientY - hostRect.top;
      if (y < header || y > hostRect.height) {
        hideGuide();
        return;
      }
      const top = Math.max(
        header,
        Math.min(y - (rowHeight / 2),
                 hostRect.height - rowHeight)
      );
      guide.style.top = `${top}px`;
      guide.style.display = "block";
      requestAnimationFrame(() => {
        guide.style.opacity = "1";
      });
      try { frame.focus({preventScroll: true}); } catch (e) { frame.focus(); }
    }

    function scrollHoriz(dx) {
      const scroller = widestScroller(frame);
      if (!scroller) return false;
      const before = scroller.scrollLeft || 0;
      scroller.scrollLeft = before + dx;
      return (scroller.scrollLeft || 0) !== before;
    }

    let dragState = null;

    function clearDrag() {
      if (dragState && dragState.dragging) {
        frame.classList.remove("w4s-ordering-dragging");
      }
      dragState = null;
    }

    function beginDragCandidate(ev) {
      if (ev.button !== 0 || isEditableTarget(ev.target)) return;
      const scroller = widestScroller(frame);
      if (!scroller || (scroller.scrollWidth - scroller.clientWidth) <= 12) {
        return;
      }
      dragState = {
        pointerId: ev.pointerId,
        startX: ev.clientX,
        startY: ev.clientY,
        startScrollLeft: scroller.scrollLeft || 0,
        scroller,
        dragging: false,
      };
    }

    function handlePointerMove(ev) {
      if (!dragState || ev.pointerId !== dragState.pointerId) return;
      if ((ev.buttons & 1) !== 1) {
        clearDrag();
        return;
      }
      const dx = ev.clientX - dragState.startX;
      const dy = ev.clientY - dragState.startY;
      if (!dragState.dragging) {
        if (Math.abs(dx) < 8 || Math.abs(dx) < Math.abs(dy) * 1.2) {
          return;
        }
        dragState.dragging = true;
        frame.classList.add("w4s-ordering-dragging");
      }
      dragState.scroller.scrollLeft = dragState.startScrollLeft - dx;
      ev.preventDefault();
      ev.stopPropagation();
    }

    frame.addEventListener("pointerdown", (ev) => {
      showGuide(ev);
      beginDragCandidate(ev);
    }, true);
    frame.addEventListener("pointerleave", hideGuide, true);
    frame.addEventListener("blur", hideGuide, true);
    frame.addEventListener("wheel", (ev) => {
      const sideways = Math.abs(ev.deltaX) > Math.abs(ev.deltaY);
      if (!ev.shiftKey && !sideways) {
        hideGuide();
        return;
      }
      const dx = sideways ? ev.deltaX : ev.deltaY;
      if (!dx) return;
      if (scrollHoriz(dx)) {
        ev.preventDefault();
        ev.stopPropagation();
      }
    }, {passive: false, capture: true});

    doc.addEventListener("keydown", (ev) => {
      const active = doc.activeElement;
      const tag = (active && active.tagName || "").toUpperCase();
      if (["INPUT", "TEXTAREA", "SELECT"].includes(tag)
          || (active && active.isContentEditable)) {
        return;
      }
      const gridHasFocus = active === frame || frame.contains(active);
      const gridIsHovered = frame.matches(":hover");
      if (!gridHasFocus && !gridIsHovered) return;
      if (["ArrowUp", "ArrowDown", "PageUp", "PageDown", "Escape"].includes(
          ev.key)) {
        hideGuide();
      }
      const plainBodyFocus = active === doc.body || active === null;
      const modified = ev.shiftKey || ev.altKey || ev.metaKey;
      if (ev.key === "ArrowRight" && (modified || plainBodyFocus)) {
        if (scrollHoriz(ev.shiftKey ? 260 : 160)) ev.preventDefault();
      } else if (ev.key === "ArrowLeft" && (modified || plainBodyFocus)) {
        if (scrollHoriz(ev.shiftKey ? -260 : -160)) ev.preventDefault();
      } else if ((ev.key === "Home" || ev.key === "End") && modified) {
        const scroller = widestScroller(frame);
        if (scroller) {
          scroller.scrollLeft = ev.key === "Home" ? 0 : scroller.scrollWidth;
          ev.preventDefault();
        }
      }
    }, true);
    doc.addEventListener("pointermove", handlePointerMove, true);
    doc.addEventListener("pointerup", clearDrag, true);
    doc.addEventListener("pointercancel", clearDrag, true);
    doc.addEventListener("pointerdown", (ev) => {
      if (!frame.contains(ev.target)) hideGuide();
    }, true);
    return true;
  }

  if (!install()) {
    setTimeout(install, 300);
    setTimeout(install, 900);
  }
})();
</script>
""" % _anchor_js, height=0)


# ---------------------------------------------------------------------------
# Sidebar
