def _freshness_from_output_dir() -> tuple:
    """Return (latest_mtime, minutes_ago, source_filename) from the most
    recently-written near-sync file (stock_on_hand is the heartbeat).
    Returns (None, None, None) if nothing found."""
    try:
        candidates = list(OUTPUT_DIR.glob("stock_on_hand_*.csv"))
        if not candidates:
            return (None, None, None)
        latest = max(candidates, key=lambda p: p.stat().st_mtime)
        mtime = datetime.fromtimestamp(latest.stat().st_mtime)
        age_min = (datetime.now() - mtime).total_seconds() / 60.0
        return (mtime, age_min, latest.name)
    except Exception:
        return (None, None, None)


def _ordering_engine_input_freshness() -> list[dict]:
    """Freshness for the source files that make Ordering trustworthy."""
    specs = [
        ("Sale lines 30d", "sale_lines_last_30d", 30.0),
        ("FG assemblies 30d", "assemblies_last_30d", 30.0),
        ("ABC cache", "engine_output", 24.0),
    ]
    rows = []
    now = datetime.now()
    for label, prefix, cadence_h in specs:
        try:
            path = catalog_latest_file(prefix, OUTPUT_DIR)
            if path is None:
                rows.append({
                    "label": label,
                    "status": "missing",
                    "icon": "🔴",
                    "age": "missing",
                    "file": "",
                })
                continue
            mtime = datetime.fromtimestamp(path.stat().st_mtime)
            age_h = (now - mtime).total_seconds() / 3600.0
            if age_h > cadence_h * 2:
                status, icon = "stale", "🔴"
            elif age_h > cadence_h:
                status, icon = "aging", "🟡"
            else:
                status, icon = "fresh", "🟢"
            rows.append({
                "label": label,
                "status": status,
                "icon": icon,
                "age": _sidebar_age_label(mtime),
                "file": path.name,
            })
        except Exception:  # noqa: BLE001
            rows.append({
                "label": label,
                "status": "unavailable",
                "icon": "🟡",
                "age": "unavailable",
                "file": "",
            })
    return rows


def _render_ordering_engine_input_freshness() -> None:
    rows = _ordering_engine_input_freshness()
    bits = [
        f"{r['icon']} {r['label']}: {r['age']}"
        for r in rows
    ]
    message = "Engine inputs · " + " · ".join(bits)
    bad = [
        r for r in rows
        if r.get("status") in {"missing", "stale", "unavailable"}
    ]
    if bad:
        st.warning(
            message
            + " — Ordering, slow-stock, and AI demand answers depend on "
              "fresh sale-lines plus 30-day Finished Goods assemblies.",
            icon="⚠️",
        )
    else:
        st.caption(message)


# The sidebar's demand-capture form needs `products` loaded so it can
# build the SKU/name autocomplete. Streamlit runs the script top-to-
# bottom — if we delay loading products until below the sidebar
# block, the form sees an undefined name, the try/except silently
# catches it, and the autocomplete is permanently empty. So load it
# here. The disk-persisted @st.cache_data on load() means this is
# essentially free on subsequent renders.
products = load("products")
# v2.61.1: customers loaded eagerly so the demand-capture form's customer
# typeahead (in the sidebar block below) has something to filter against.
# Same disk-cache treatment as products — the duplicate load() further
# down is essentially free.
customers = load("customers")


def _sidebar_age_label(dt: datetime) -> str:
    age_min = (datetime.now() - dt).total_seconds() / 60.0
    if age_min < 1:
        return "just now"
    if age_min < 60:
        return f"{age_min:.0f}m ago"
    if age_min < 1440:
        return f"{age_min / 60:.1f}h ago"
    return f"{age_min / 1440:.1f}d ago"


def _sidebar_abc_status() -> str:
    try:
        eng_path = OUTPUT_DIR / "engine_output.csv"
        lock_path = OUTPUT_DIR / "engine_refresh.lock"
        eng_mtime = eng_path.stat().st_mtime if eng_path.exists() else None
        refresh_running = False
        if lock_path.exists():
            lock_age_min = (
                datetime.now().timestamp() - lock_path.stat().st_mtime
            ) / 60.0
            refresh_running = lock_age_min <= 45
        if refresh_running:
            if eng_mtime:
                eng_at = datetime.fromtimestamp(eng_mtime)
                return (
                    "🟡 ABC refresh running · using "
                    f"{eng_at.strftime('%Y-%m-%d %H:%M')}"
                )
            return "🟡 ABC refresh running · first snapshot pending"
        if eng_mtime:
            eng_at = datetime.fromtimestamp(eng_mtime)
            age_min = (datetime.now() - eng_at).total_seconds() / 60.0
            icon = "🟢" if age_min < 1440 else "🟡"
            return f"{icon} ABC updated {_sidebar_age_label(eng_at)}"
        return "🟡 ABC snapshot not yet created"
    except Exception:  # noqa: BLE001
        return "ABC status unavailable"


def _sidebar_sync_status() -> str:
    _, age_min, filename = _freshness_from_output_dir()
    if age_min is None:
        return "🟡 CIN7 sync status unavailable"
    icon = "🟢" if age_min <= 30 else "🟡" if age_min <= 180 else "🔴"
    if age_min < 60:
        age = f"{age_min:.0f}m ago"
    elif age_min < 1440:
        age = f"{age_min / 60:.1f}h ago"
    else:
        age = f"{age_min / 1440:.1f}d ago"
    suffix = f" · {filename}" if filename else ""
    return f"{icon} CIN7 sync {age}{suffix}"


def _clear_app_caches_for_sidebar() -> None:
    _safe_cache_clear()
    try:
        st.cache_resource.clear()
    except Exception:  # noqa: BLE001
        pass
    st.session_state.pop("_engine_df_cached", None)


def _visible_pages_for_profile(profile: dict) -> list[str]:
    page_options = list(PAGE_OPTIONS)
    user_role = (profile or {}).get("role") or "sales"
    user_id = (profile or {}).get("user_id") or 0
    user_name = (
        (profile or {}).get("display_name")
        or st.session_state.get("current_user", "")
    )
    is_super_admin = db.is_super_admin(user_name, user_role)
    if is_super_admin:
        return page_options
    if (user_role or "").strip().lower() == "admin":
        return [p for p in page_options if p != "User Permissions"]
    try:
        return [
            p for p in page_options
            if (
                p != "User Permissions"
                and db.can_user_access_page(user_id, p, user_role)
            )
        ]
    except Exception:
        return [p for p in page_options if p != "User Permissions"]


with st.sidebar:
    st.title(":bar_chart: Cin7 Analytics")
    st.caption("Wired4Signs USA, LLC — ops dashboard")
    st.caption(_sidebar_abc_status())
    st.caption(_sidebar_sync_status())
    # Detailed release history lives in GitHub; keep the primary
    # sidebar focused on daily work rather than changelog text.
    # Old v2.66.2 caption kept here for reference, hidden:
    _ = (
        "🟢 v2.66.2 — Slow-stock rule tightened, MAX_TURNS bumped 6 to 10. "
        "v2.66's slow-stock promotion was making Claude call "
        "get_relevant_slow_stock on non-product questions (similarity, "
        "sales totals, velocity), exhausting the 6-turn LLM loop budget "
        "and producing the empty 'I couldn't answer that' fallback. "
        "Three fixes: (1) the rule now triggers ONLY on product-LIST "
        "queries; explicitly forbidden for similarity / single-SKU / "
        "sales-totals / velocity / demand-signal / incoming-stock / "
        "accessory / dead-stock-review questions. (2) Claude is told "
        "to NEVER narrate the tool call — no 'let me check for "
        "slow-moving stock' lead-in mid-stream. The section either "
        "lands at the end with results or doesn't appear at all. "
        "(3) MAX_TURNS bumped 6 to 10 to give the loop comfortable "
        "headroom. Carries v2.66 forward unchanged: users / profiles "
        "schema, sidebar sign-in picker (selectbox + 'Add new user' "
        "form, no free-text), My Profile page, default_page jump, "
        "user.login audit, get_relevant_slow_stock tool."
    )

    # --- SKU-rename pending indicator ------------------------------------
    # When the team renames a SKU in CIN7 (catalog code prefix, version
    # suffix, etc.), our local DB references go stale. This badge fires
    # when the latest two products_*.csv files differ on any SKU AND the
    # old SKU still has live references in our DB tables. Click-through
    # tells the buyer exactly what to do.
    @st.cache_data(ttl=300, show_spinner=False)
    def _detect_pending_renames() -> list:
        """Compares two latest products CSVs by ProductID, returns list
        of (old_sku, new_sku, name, has_db_refs) for renames that still
        have references in our DB (i.e., not yet propagated)."""
        files = sorted(OUTPUT_DIR.glob("products_*.csv"),
                        key=lambda p: p.stat().st_mtime)
        if len(files) < 2:
            return []
        try:
            old_df = pd.read_csv(files[-2], low_memory=False)
            new_df = pd.read_csv(files[-1], low_memory=False)
        except Exception:
            return []
        old_idx = {str(r["ID"]): str(r["SKU"])
                    for _, r in old_df.iterrows()
                    if pd.notna(r.get("ID")) and pd.notna(r.get("SKU"))}
        renames = []
        for _, r in new_df.iterrows():
            pid = str(r.get("ID") or "")
            new_sku = str(r.get("SKU") or "")
            if not pid or not new_sku:
                continue
            old_sku = old_idx.get(pid)
            if old_sku and old_sku != new_sku:
                # Check if old_sku still has references in DB
                has_refs = False
                try:
                    with db.connect() as c:
                        # Check the most likely tables
                        for tbl, col in [
                            ("sku_migrations", "retiring_sku"),
                            ("sku_migrations", "successor_sku"),
                            ("sku_supplier_overrides", "sku"),
                            ("sku_policy_overrides", "sku"),
                            ("sku_pack_settings", "sku"),
                            ("notes", "sku"),
                            ("flags", "sku"),
                            ("family_critical_components", "component_sku"),
                        ]:
                            n = c.execute(
                                f"SELECT COUNT(*) AS n FROM {tbl} "
                                f"WHERE {col} = ?",
                                (old_sku,)).fetchone()
                            if n["n"] > 0:
                                has_refs = True
                                break
                except Exception:
                    has_refs = False
                renames.append({
                    "old": old_sku, "new": new_sku,
                    "name": str(r.get("Name") or "")[:50],
                    "has_db_refs": has_refs,
                })
        return renames

    _pending = _detect_pending_renames()
    if _pending:
        _with_refs = [r for r in _pending if r["has_db_refs"]]
        if _with_refs:
            st.warning(
                f":wrench: **{len(_with_refs)} SKU rename"
                f"{'s' if len(_with_refs) != 1 else ''} pending** "
                f"propagation to local DB.  \n"
                f"CIN7 source-of-truth shifted; our DB still references "
                f"the old SKU"
                f"{'s' if len(_with_refs) != 1 else ''}.  \n"
                f"Run: `python sync_sku_renames.py --apply`")
        else:
            st.caption(
                f":sparkles: {len(_pending)} SKU rename"
                f"{'s' if len(_pending) != 1 else ''} detected since last "
                f"products sync (no DB references — informational only).")

    st.divider()

    # ---- Sign-in: name + profile (v2.66) ----
    # The shared APP_PASSWORD gate above unlocks the app; this is who
    # the user IS within the team. Typeahead against the users table
    # so existing profiles are picked rather than re-typed; new names
    # auto-create a basic profile (role=sales) on first sign-in. The
    # picked profile is stashed in session_state so forms can read
    # display_name + role + default_page.
    try:
        _user_rows = db.list_users(active_only=True)
    except Exception:
        _user_rows = []
    _existing_names = [r["display_name"] for r in _user_rows]

    # v2.67.302+ — persistent sign-in across Render deploys. The
    # password gate restores this before the sidebar renders; this
    # extra call keeps local-dev/no-password mode compatible.
    _restore_user_session_from_url()
    # Periodically prune expired rows (cheap — single DELETE
    # bounded by the index). Best-effort.
    try:
        db.cleanup_expired_user_sessions()
    except Exception:  # noqa: BLE001
        pass

    _signed_in_name = st.session_state.get("current_user") or ""
    if _signed_in_name and _signed_in_name in _existing_names:
        # Already signed in this session — show selected profile + a
        # "Sign out" button rather than the picker.
        _profile = (st.session_state.get("current_user_profile")
                    or {})
        _role = _profile.get("role", "sales")
        st.success(
            f"👤 **{_signed_in_name}** "
            f"(`{_role}`)")
        if st.button("Sign out", key="_signout_btn",
                      width="stretch"):
            # v2.67.302 — revoke the persistent session token AND
            # clear the URL param, otherwise a refresh would
            # silently restore the just-signed-out user.
            try:
                _tok = st.session_state.get("_session_token") or ""
                if _tok:
                    db.revoke_user_session(_tok)
            except Exception:  # noqa: BLE001
                pass
            try:
                if "sid" in st.query_params:
                    del st.query_params["sid"]
            except Exception:  # noqa: BLE001
                pass
            for _k in ("current_user",
                        "current_user_id",
                        "current_user_profile",
                        "_session_token",
                        "_app_authed",
                        "_signin_pending_name",
                        "_default_page_consumed"):
                st.session_state.pop(_k, None)
            st.rerun()
    else:
        # v2.66.1: split sign-in into two distinct flows so an existing
        # team member can never accidentally create a duplicate
        # profile by typing a slightly-different version of their
        # name. Primary path = selectbox of existing users; secondary
        # path = explicit 'Add new user' expander.
        if not _existing_names:
            st.info(
                ":information_source: No users registered yet. "
                "Use 'Add new user' below to create the first "
                "profile.")
            _picked = ""
        else:
            _picked = st.selectbox(
                "Sign in as",
                options=["(select your name)"] + _existing_names,
                index=0,
                key="_signin_picker",
                help="Pick your name from the list of registered "
                     "users. Use 'Add new user' below if you're not "
                     "yet on the team.")
            if _picked != "(select your name)":
                if st.button(":unlock: Sign in",
                              type="primary", width="stretch",
                              key="_signin_btn"):
                    try:
                        _user = db.get_user_by_name(_picked)
                        if _user is None:
                            st.error(
                                f"Profile for `{_picked}` not found. "
                                "Try the 'Add new user' flow.")
                        else:
                            _complete_user_signin(
                                _user, detail=f"role={_user['role']}")
                            st.success(
                                f":white_check_mark: Welcome, "
                                f"**{_user['display_name']}** "
                                f"(`{_user['role']}`)")
                            st.rerun()
                    except Exception as _e:
                        st.error(f"Sign-in failed: {_e}")

        # Add new user — separate expander to keep first-time signup
        # off the primary sign-in path (so existing users don't
        # accidentally create dup profiles by typing a slight
        # variation of their name).
        with st.expander(":heavy_plus_sign: Add new user",
                          expanded=not _existing_names):
            with st.form("_signup_form", clear_on_submit=False):
                _new_name = st.text_input(
                    "Name", placeholder="e.g. James",
                    key="_signup_name")
                # v2.67.207 — self-signup can ONLY pick a non-
                # privileged role. admin / super_admin must be
                # granted by a super-admin afterwards on the
                # User Permissions page. Without this, anyone at
                # the sign-in gate could create themselves a
                # super_admin profile.
                _self_signup_roles = [
                    r for r in db.USER_ROLES
                    if r not in ("admin", "super_admin")]
                _new_role = st.selectbox(
                    "Role", options=_self_signup_roles,
                    index=(_self_signup_roles.index("sales")
                              if "sales" in _self_signup_roles
                              else 0),
                    key="_signup_role",
                    help="buyer / sales / viewer. Admin access "
                         "is granted separately by a super-admin "
                         "— it can't be self-assigned.")
                _signup_submit = st.form_submit_button(
                    ":sparkles: Create profile and sign in",
                    type="primary", width="stretch")
            if _signup_submit:
                _name_clean = (_new_name or "").strip()
                if not _name_clean:
                    st.error("Name is required.")
                elif _name_clean in _existing_names:
                    st.error(
                        f"`{_name_clean}` already exists — use the "
                        "Sign in flow above to log in as them, or "
                        "pick a different name.")
                else:
                    try:
                        _uid = db.upsert_user(
                            display_name=_name_clean,
                            role=_new_role,
                            active=True,
                            actor=_name_clean)
                        _user = db.get_user_by_name(_name_clean)
                        if _user is not None:
                            _complete_user_signin(
                                _user, detail="via signup")
                            st.success(
                                f":white_check_mark: Profile created. "
                                f"Welcome, **{_user['display_name']}**"
                                f" (`{_user['role']}`)")
                            st.rerun()
                    except Exception as _e:
                        st.error(f"Signup failed: {_e}")

        # Stop the rest of the sidebar from rendering until they sign
        # in — the demand-capture form, page nav, etc. all rely on
        # current_user being set so the audit trail is honest.
        st.stop()

    # Past this point: someone is signed in. Convenience refs.
    current_user = st.session_state.get("current_user", "")
    current_user_profile = (
        st.session_state.get("current_user_profile") or {})

    # ---- Slack OAuth callback handler (v2.67.126) --------------------
    # When a user clicks "Connect Slack" on the My Profile page, they
    # are redirected to Slack to authorise, then Slack redirects back
    # to this app with ?slack_oauth=callback&code=...&state=... in the
    # query string. We need to process that BEFORE any page renders so
    # the token is stored and the URL is cleaned up.
    try:
        _qp = dict(st.query_params)
    except Exception:
        _qp = {}
    if _qp.get("slack_oauth") == "callback" and _qp.get("code"):
        _expected_state = st.session_state.get(
            "_slack_oauth_state") or ""
        _received_state = _qp.get("state") or ""
        if _expected_state and _received_state != _expected_state:
            st.error(":lock: Slack OAuth state mismatch — possible "
                       "CSRF. Try connecting again.")
            try:
                st.query_params.clear()
            except Exception:
                pass
        else:
            try:
                import slack_oauth as _slack_oauth
                _oauth_body = _slack_oauth.exchange_code_for_token(
                    _qp.get("code"))
                if _oauth_body:
                    _slack_oauth.store_user_token_from_oauth(
                        user_id=current_user_profile.get("user_id"),
                        oauth_response=_oauth_body)
                    st.success(
                        ":white_check_mark: Slack connected. The "
                        "dashboard can now ask Viktor on your "
                        "behalf for marketing questions.")
                else:
                    st.error(
                        ":x: Slack OAuth exchange failed. Check "
                        "the worker logs for slack_oauth errors.")
            except Exception as _exc:  # noqa: BLE001
                st.error(f":x: Slack OAuth error: {_exc}")
            finally:
                # Clear query params so a refresh doesn't re-process
                # the (now-used) code.
                try:
                    st.query_params.clear()
                except Exception:
                    pass
                st.session_state.pop("_slack_oauth_state", None)

    # ---- QuickBooks Online OAuth callback handler (v2.67.211) --------
    # When a super-admin clicks "Connect QuickBooks Online", Intuit
    # redirects back here with ?qbo_oauth=callback&code=...&state=...
    # &realmId=... — realmId identifies which QBO company file was
    # authorised. Process it before any page renders, then clean the
    # URL so a refresh doesn't replay the (single-use) code.
    if _qp.get("qbo_oauth") == "callback" and _qp.get("code"):
        _expected_qbo_state = st.session_state.get(
            "_qbo_oauth_state") or ""
        _received_qbo_state = _qp.get("state") or ""
        if (_expected_qbo_state
                and _received_qbo_state != _expected_qbo_state):
            st.error(":lock: QuickBooks OAuth state mismatch — "
                       "possible CSRF. Try connecting again.")
            try:
                st.query_params.clear()
            except Exception:
                pass
            st.session_state.pop("_qbo_oauth_state", None)
        else:
            try:
                import qbo_oauth as _qbo_oauth
                _realm = (_qp.get("realmId")
                           or _qp.get("realmid") or "")
                _qbo_oauth.exchange_code_for_token(
                    code=_qp.get("code"),
                    realm_id=_realm,
                    connected_by=current_user or None)
                st.success(
                    ":white_check_mark: QuickBooks Online "
                    "connected. The Cashflow Management page can "
                    "now read your books.")
            except Exception as _exc:  # noqa: BLE001
                st.error(f":x: QuickBooks OAuth error: {_exc}")
            finally:
                try:
                    st.query_params.clear()
                except Exception:
                    pass
                st.session_state.pop("_qbo_oauth_state", None)

    # ---- Navigation -----------------------------------------------------
    st.divider()
    st.subheader("Navigate")
    _visible_pages = _visible_pages_for_profile(current_user_profile)
    if not _visible_pages:
        st.error("No pages are available for your profile.")
        st.stop()

    _default_page = (current_user_profile or {}).get("default_page")
    _previous_page = st.session_state.get("_sidebar_selected_page")
    if (_default_page
            and _default_page in _visible_pages
            and not st.session_state.get("_default_page_consumed")):
        _initial_page = _default_page
        st.session_state["_default_page_consumed"] = True
    elif _previous_page in _visible_pages:
        _initial_page = _previous_page
    else:
        _initial_page = _visible_pages[0]

    _visible_groups = [
        group for group, pages in PAGE_GROUPS.items()
        if any(p in _visible_pages for p in pages)
    ]
    _initial_group = PAGE_GROUP_BY_NAME.get(
        _initial_page, _visible_groups[0])
    _group_index = (
        _visible_groups.index(_initial_group)
        if _initial_group in _visible_groups else 0)
    _nav_group = st.selectbox(
        "Section",
        options=_visible_groups,
        index=_group_index,
        key="_sidebar_nav_group",
    )
    _group_pages = [
        p for p in PAGE_GROUPS.get(_nav_group, [])
        if p in _visible_pages
    ]
    _page_index = (
        _group_pages.index(_initial_page)
        if _initial_page in _group_pages else 0)
    page = st.radio(
        "Page",
        _group_pages,
        index=_page_index,
        key=f"_sidebar_nav_page_{_nav_group}",
    )
    st.session_state["_sidebar_selected_page"] = page
    st.caption(PAGE_DESCRIPTIONS.get(page, ""))

    with st.expander("All pages", expanded=False):
        for _group, _pages in PAGE_GROUPS.items():
            _group_pages = [p for p in _pages if p in _visible_pages]
            if not _group_pages:
                continue
            st.markdown(f"**{_group}**")
            for _opt in _group_pages:
                _cap = PAGE_DESCRIPTIONS.get(_opt, "")
                st.markdown(
                    f"- **{_opt}** — <small>{_cap}</small>",
                    unsafe_allow_html=True)

    # ---- Global controls ------------------------------------------------
    st.divider()
    st.subheader("Controls")
    stock_only = st.toggle(
        "Stock items only",
        value=True,
        help="Hide Service and Non-Inventory items from stock / reorder "
             "analysis. Recommended default. Uncheck to see everything.",
    )

    with st.expander("Data controls", expanded=False):
        st.caption(_sidebar_abc_status())
        st.caption(_sidebar_sync_status())
        if st.button(
            ":arrows_counterclockwise: Reload local data",
            width="stretch",
            help="Clear in-app caches and reload from the CSV snapshots "
                 "already on the server. CIN7 sync itself runs in the "
                 "background.",
        ):
            _clear_app_caches_for_sidebar()
            st.rerun()
        st.caption(
            "Automatic sync and ABC refresh run in the background. "
            "Use reload only if the screen looks stale.")
        st.caption(
            f":email: Support: {_LEGAL_CONTACT_EMAIL}")

    # ---- Quick-capture demand signal ----------------------------------
    # Available from every page so sales/buyers can log a customer
    # inquiry, quote request, lost sale, etc. in 15 seconds without
    # navigating. Foundation for the proactive intelligence layer —
    # see docs/demand-scoring.md (when built) and NEXT_STEPS.md.
    with st.expander(":bulb: Capture demand signal", expanded=False):
        st.caption(
            "Log a customer inquiry, quote, lost sale, etc. Every "
            "signal feeds the buyer's reorder warnings.")
        _ds_actor = (st.session_state.get("current_user") or "").strip()
        if not _ds_actor:
            st.warning(
                "Enter your name above first — signals need an "
                "author for audit logging.")
        else:
            # SKU autocomplete from products (already loaded)
            try:
                _sku_options = (
                    sorted(products["SKU"].dropna().astype(str).unique())
                    if not products.empty and "SKU" in products.columns
                    else [])
            except Exception:
                _sku_options = []
            # ---- Smart SKU search (OUTSIDE the form so it can be
            # reactive — clicking a suggestion re-runs and updates the
            # text input). Lets the user paste, type freely, and pick
            # from live-filtered matches.
            #
            # Streamlit gotcha: you CANNOT do
            # `st.session_state[widget_key] = value` AFTER the widget
            # has been rendered in this run — it raises "cannot be
            # modified after the widget is instantiated". Workaround:
            # any state change must happen BEFORE the widget renders,
            # OR use an on_click callback (which runs pre-render on
            # the next cycle).
            _sku_upper = {s.upper(): s for s in _sku_options}
            _sku_text_key = "_ds_sku_text"

            # Apply any pending value queued by a suggestion button or
            # by the post-save "clear" flow. This runs BEFORE the
            # text_input below, so it's allowed.
            if "_ds_sku_pending" in st.session_state:
                st.session_state[_sku_text_key] = (
                    st.session_state.pop("_ds_sku_pending"))

            if _sku_text_key not in st.session_state:
                st.session_state[_sku_text_key] = ""

            _ds_sku_typed = st.text_input(
                "Search by SKU OR product name",
                key=_sku_text_key,
                placeholder="Paste a SKU, or type any part of the "
                            "product name (e.g. 'slim8 black 2m')…",
                help="Searches both SKU and product name. Type as "
                     "much or as little as you need; click a "
                     "suggestion to fill, or just submit with what "
                     "you typed.")

            # Live status / suggestions based on what they typed.
            # The search now treats SKU and Name equally — type any
            # word from the product name OR any part of the SKU and
            # we surface matches. Multi-strategy:
            #   1. EXACT SKU (case-insensitive)
            #   2. SKU prefix
            #   3. SKU substring (forward + reverse for variant pastes)
            #   4. NAME — every word the user typed must appear in the
            #      product name (so 'slim8 black 2m' narrows down)
            #   5. FUZZY SKU (typo-tolerant via difflib)
            _ds_sku_resolved = ""
            _q = (_ds_sku_typed or "").strip()
            if _q:
                import difflib as _difflib
                _q_upper = _q.upper()
                if _q_upper in _sku_upper:
                    # Exact SKU match — confirmation banner
                    _ds_sku_resolved = _sku_upper[_q_upper]
                    try:
                        _name = (products[products["SKU"] ==
                                            _ds_sku_resolved]
                                  ["Name"].iloc[0])
                        st.caption(
                            f":white_check_mark: **{_ds_sku_resolved}** — "
                            f"{str(_name)[:80]}")
                    except (IndexError, KeyError):
                        st.caption(
                            f":white_check_mark: {_ds_sku_resolved}")
                else:
                    _all_skus_upper = list(_sku_upper.keys())
                    # 2. SKU prefix
                    _prefix = [s for s in _sku_options
                                if s.upper().startswith(_q_upper)]
                    # 3a. SKU substring forward
                    _sub_fwd = [s for s in _sku_options
                                 if _q_upper in s.upper()
                                 and s not in _prefix]
                    # 3b. SKU substring reverse (catches variant
                    # pastes like LED-XYZ-2 when catalog has LED-XYZ)
                    _sub_rev = [s for s in _sku_options
                                 if len(s) >= 6
                                 and s.upper() in _q_upper
                                 and s not in _prefix
                                 and s not in _sub_fwd]
                    # 4. NAME match — every space-separated word the
                    # user typed must appear in the product name
                    # (case-insensitive, word-soup friendly).
                    # Example: typing "slim8 black 2m" finds
                    # 'Slim LED Channel ~ Model Slim8 (Black, 2m)'
                    _name_hits: list = []
                    try:
                        if (not products.empty
                                and "Name" in products.columns
                                and "SKU" in products.columns):
                            _words = [w for w in _q.split()
                                       if len(w) >= 2]
                            if _words:
                                _name_series = (
                                    products["Name"].astype(str)
                                    .str.lower())
                                _mask = pd.Series(
                                    [True] * len(products),
                                    index=products.index)
                                for _w in _words:
                                    _mask &= _name_series.str.contains(
                                        _w.lower(), na=False, regex=False)
                                _name_hits = (
                                    products[_mask]["SKU"]
                                    .dropna().astype(str).head(20).tolist())
                                # Drop ones already in earlier buckets
                                _seen = set(_prefix + _sub_fwd + _sub_rev)
                                _name_hits = [
                                    s for s in _name_hits
                                    if s and s not in _seen]
                    except Exception:
                        pass
                    # 5. Fuzzy SKU (typo-tolerant)
                    _close = _difflib.get_close_matches(
                        _q_upper, _all_skus_upper, n=4, cutoff=0.7)
                    _fuzzy = [_sku_upper[c] for c in _close
                               if c in _sku_upper
                               and _sku_upper[c] not in
                                   (_prefix + _sub_fwd + _sub_rev
                                    + _name_hits)]

                    # Build final list. Order: SKU exact-ish first
                    # (prefix + sub_fwd + sub_rev), then name matches
                    # (the user knows the product, just not the SKU),
                    # then fuzzy as last resort. Cap at 12 — name
                    # searches can hit dozens.
                    _matches = (
                        _prefix + _sub_fwd + _sub_rev
                        + _name_hits + _fuzzy)[:12]
                    if _matches:
                        # Tell them WHY each match showed up so it's
                        # not magic.
                        _categories = []
                        if _prefix or _sub_fwd or _sub_rev:
                            _categories.append("SKU")
                        if _name_hits:
                            _categories.append("name")
                        if _fuzzy:
                            _categories.append("fuzzy")
                        st.caption(
                            f"_{len(_matches)} match"
                            f"{'es' if len(_matches) != 1 else ''} "
                            f"({' + '.join(_categories)})_ — click to use:")
                        for _i, _m in enumerate(_matches):
                            try:
                                _mname = (
                                    products[products["SKU"] == _m]
                                    ["Name"].iloc[0])
                                _mname = str(_mname)[:65]
                            except (IndexError, KeyError):
                                _mname = ""
                            _label = (f"{_m}  —  {_mname}"
                                      if _mname else _m)
                            if st.button(
                                    _label, key=f"_ds_pick_{_i}_{_m}",
                                    use_container_width=True):
                                # Queue the new value; it'll be applied
                                # to the widget BEFORE the next render.
                                st.session_state["_ds_sku_pending"] = _m
                                st.rerun()
                    elif len(_q) >= 2:
                        st.caption(
                            f":warning: No SKU or product-name match "
                            f"for `{_q}`. You can still save the "
                            "signal — we'll store it as free-text "
                            "(useful for new product requests or "
                            "when CIN7 hasn't synced yet).")

            # ---- Customer typeahead (OUTSIDE the form, so each keystroke
            # triggers a rerun and we can show live suggestions). Same
            # pattern as the SKU search above. The picked customer's id +
            # name are stashed in session_state and read by the form's
            # submit handler below.
            #
            # Why this matters: without a real CIN7 customer_id captured
            # here, the reconciler can't ever auto-convert (HIGH tier).
            # See db.reconcile_demand_signals — HIGH requires exact
            # customer_id match against the CIN7 sale row. Free-text
            # names are MEDIUM at best.
            _cust_text_key = "_ds_cust_text"
            if "_ds_cust_pending" in st.session_state:
                st.session_state[_cust_text_key] = (
                    st.session_state.pop("_ds_cust_pending"))
            _cust_q_raw = st.text_input(
                "Customer (search CIN7 to record customer_id)",
                placeholder="Type a name — picks the CIN7 customer",
                key=_cust_text_key,
                help="Recording the real CIN7 customer_id is what lets "
                     "the auto-reconciler later mark this signal "
                     "'converted' when the customer actually buys. "
                     "Leave blank for walk-in / unknown — the signal "
                     "still saves but stays MEDIUM-confidence at "
                     "reconcile time.")
            _cust_q = (_cust_q_raw or "").strip().lower()

            _picked_cust_id = st.session_state.get("_ds_cust_id")
            _picked_cust_name = st.session_state.get("_ds_cust_name")

            if _picked_cust_id:
                _selrow = st.columns([4, 1])
                _selrow[0].success(
                    f":busts_in_silhouette: **{_picked_cust_name}** "
                    f"`(id {_picked_cust_id})`")
                if _selrow[1].button("Clear", key="_ds_cust_clear"):
                    st.session_state["_ds_cust_id"] = None
                    st.session_state["_ds_cust_name"] = None
                    st.session_state["_ds_cust_pending"] = ""
                    st.rerun()
            elif len(_cust_q) >= 2:
                try:
                    if (not customers.empty
                            and "Name" in customers.columns):
                        _name_col = customers["Name"].fillna("").astype(str)
                        _mask = _name_col.str.lower().str.contains(
                            _cust_q, na=False)
                        _cust_matches = customers[_mask].head(8)
                        if _cust_matches.empty:
                            st.caption(
                                f":warning: No CIN7 customer matches "
                                f"`{_cust_q_raw}`. Save anyway and the "
                                f"signal will be MEDIUM-confidence "
                                f"(reviewer can pick later).")
                        else:
                            st.caption(":busts_in_silhouette: Pick the "
                                        "customer:")
                            for _, _crow in _cust_matches.iterrows():
                                _cid = str(_crow.get("ID", "") or "").strip()
                                _cname = str(
                                    _crow.get("Name", "") or "").strip()
                                if not _cid or not _cname:
                                    continue
                                if st.button(
                                        f"{_cname}  —  `{_cid}`",
                                        key=f"_ds_pick_cust_{_cid}",
                                        use_container_width=True):
                                    st.session_state["_ds_cust_id"] = _cid
                                    st.session_state["_ds_cust_name"] = _cname
                                    st.session_state["_ds_cust_pending"] = ""
                                    st.rerun()
                    else:
                        st.caption(
                            ":warning: customers CSV not loaded yet — "
                            "can't search. Save with free-text name; "
                            "the reviewer can pick a customer later.")
                except Exception as _e:
                    st.caption(f":warning: customer search failed: {_e}")

            # ---- The actual form for the rest of the fields
            with st.form("ds_form", clear_on_submit=False):
                _ds_family = st.text_input(
                    "Product family (fallback)",
                    placeholder="e.g. SIERRA38 — only if no SKU",
                    help="Used when the customer described the product "
                         "but you couldn't pin a specific SKU.")
                _ds_type = st.selectbox(
                    "Signal type",
                    options=[
                        "inquiry", "quote", "sold", "lost",
                        "substitute_offered", "cancelled", "returned",
                        "complaint", "abandoned_cart", "notify_me",
                    ],
                    help="What KIND of signal is this?")
                _ds_qty = st.number_input(
                    "Quantity (optional)",
                    min_value=0.0, value=0.0, step=1.0,
                    help="Units mentioned. 0 = unknown / N-A.")
                _ds_note = st.text_area(
                    "Note (optional)",
                    placeholder="Quick context: 'asked for warm white "
                                "to match cabinet install', etc.",
                    height=60)
                _ds_submit = st.form_submit_button(
                    "💾 Save signal", type="primary",
                    use_container_width=True)
            if _ds_submit:
                # Use whatever's in the SKU text input — exact match
                # if found, free-text otherwise.
                _ds_sku_final = (
                    _ds_sku_resolved
                    or (st.session_state[_sku_text_key] or "").strip()
                    or None)
                # Customer: prefer the picked CIN7 customer (id + name);
                # fall back to whatever the user typed in the search box
                # as free-text customer_name with NULL customer_id.
                _final_cust_id = st.session_state.get("_ds_cust_id")
                _final_cust_name = (
                    st.session_state.get("_ds_cust_name")
                    or (st.session_state.get(_cust_text_key) or "").strip()
                    or None)
                if not _ds_sku_final and not _ds_family.strip():
                    st.error(
                        "Need either a SKU or a product family. "
                        "Signals without a target product can't drive "
                        "buyer warnings.")
                else:
                    try:
                        _new_id = db.insert_demand_signal(
                            source="manual",
                            signal_type=_ds_type,
                            sku=_ds_sku_final,
                            product_family=(
                                _ds_family.strip().upper() or None),
                            quantity=float(_ds_qty) if _ds_qty > 0 else None,
                            customer_id=_final_cust_id,
                            customer_name=_final_cust_name,
                            salesperson=_ds_actor,
                            note=_ds_note.strip() or None,
                            confidence=1.0,
                            created_by=_ds_actor,
                        )
                        st.success(
                            f":white_check_mark: Signal #{_new_id} "
                            f"saved for **{_ds_sku_final or _ds_family}**"
                            + (f" → {_final_cust_name}"
                               if _final_cust_name else "")
                            + ".")
                        # Queue clearing both the SKU search AND the
                        # customer selection so the next capture starts
                        # fresh. Direct assignment would error because
                        # the widget is already instantiated this run.
                        st.session_state["_ds_sku_pending"] = ""
                        st.session_state["_ds_cust_pending"] = ""
                        st.session_state["_ds_cust_id"] = None
                        st.session_state["_ds_cust_name"] = None
                        st.rerun()
                    except Exception as _exc:
                        st.error(f"Could not save: {_exc}")

        # Show last 5 signals as confirmation / context
        try:
            _recent = db.list_demand_signals(limit=5)
            if _recent:
                st.caption("Last 5 captured")
                for _r in _recent:
                    _dict = dict(_r)
                    _line = (
                        f"`{_dict.get('signal_type', '?')}` · "
                        f"{_dict.get('sku') or _dict.get('product_family') or '?'} · "
                        f"{_dict.get('customer_name') or ''} · "
                        f"_{_dict.get('created_by') or '?'}_"
                    )
                    st.markdown(f"- {_line}")
        except Exception:
            pass


