# Why this pattern: persist="disk" caches don't support ttl. To get
# auto-invalidation on fresh data, the cache key must change when the
# file list changes. _dir_fingerprint() returns a hashable tuple of
# (name, mtime) pairs — used as a cache-busting argument so the inner
# cached function rebuilds when the daily sync drops a new CSV.
def _dir_fingerprint(pattern: str) -> tuple:
    """Return a deterministic fingerprint of all files matching the
    glob pattern in OUTPUT_DIR. Used as a cache key so persisted
    caches invalidate automatically when files change."""
    out = []
    for p in sorted(OUTPUT_DIR.glob(pattern)):
        try:
            out.append((p.name, p.stat().st_mtime))
        except OSError:
            continue
    return tuple(out)


def _engine_source_fingerprint() -> tuple:
    """Fingerprint every source file that feeds the ABC engine."""
    return (
        _dir_fingerprint("products_*.csv"),
        _dir_fingerprint("stock_on_hand_*.csv"),
        _dir_fingerprint("sale_lines_last_*d_*.csv"),
        _dir_fingerprint("purchase_lines_last_*d_*.csv"),
        _dir_fingerprint("assemblies_last_*d_*.csv"),
    )


def _fingerprint_latest_mtime(fp: tuple) -> float:
    """Return the newest mtime embedded in a nested fingerprint."""
    newest = 0.0
    for group in fp:
        for _, mtime in group:
            try:
                newest = max(newest, float(mtime or 0))
            except (TypeError, ValueError):
                continue
    return newest


_ENGINE_OUTPUT_PATH = OUTPUT_DIR / "engine_output.csv"
_ENGINE_REFRESH_LOCK = OUTPUT_DIR / "engine_refresh.lock"
_ENGINE_REFRESH_STATUS = OUTPUT_DIR / "engine_refresh_status.json"
_ENGINE_REFRESH_LOG = OUTPUT_DIR / "engine_refresh.log"
_STOCK_LOCATOR_COLUMNS = (
    "StockLocator",
    "Stock Locator",
    "Stock locator",
    "stock_locator",
)


@st.cache_data(ttl=300, show_spinner=False)
def _cached_live_product_movements_for_sku(sku: str) -> dict:
    """Return CIN7 product Movements for one SKU when live creds exist.

    Used only in selected-SKU drill-ins. It is intentionally not applied
    to the whole Ordering grid because that would require one CIN7 API
    call per row on every rerun.
    """
    try:
        import ai_tools as _ai_tools
        return _ai_tools._get_live_product_movements(str(sku or ""))
    except Exception as exc:  # noqa: BLE001
        return {
            "ok": False,
            "reason": f"live product movement lookup failed: {exc}",
        }


def _engine_output_mtime() -> Optional[float]:
    try:
        if _ENGINE_OUTPUT_PATH.exists():
            return _ENGINE_OUTPUT_PATH.stat().st_mtime
    except OSError:
        return None
    return None


def _parse_engine_list_cell(value):
    if isinstance(value, list):
        return value
    if value is None or pd.isna(value):
        return []
    text = str(value).strip()
    if not text.startswith("["):
        return []
    try:
        parsed = ast.literal_eval(text)
    except (SyntaxError, ValueError):
        return []
    if not isinstance(parsed, list):
        return []
    out = []
    for item in parsed:
        try:
            out.append(float(item))
        except (TypeError, ValueError):
            out.append(0.0)
    return out


def _parse_engine_bool_cell(value) -> bool:
    if value is None or pd.isna(value):
        return False
    if isinstance(value, bool):
        return value
    text = str(value).strip().lower()
    if text in {"true", "1", "yes", "y"}:
        return True
    if text in {"false", "0", "no", "n", ""}:
        return False
    return bool(value)


def _normalise_engine_snapshot(df: pd.DataFrame) -> pd.DataFrame:
    """Restore CSV-loaded engine snapshot columns to app-friendly types."""
    if df.empty:
        return df
    ensure_storage_dim_column(df)
    for col in ("trend_12m", "trend_24m"):
        if col in df.columns:
            df[col] = df[col].apply(_parse_engine_list_cell)
    for col in ("is_dormant", "is_non_master_tube"):
        if col in df.columns:
            df[col] = df[col].apply(_parse_engine_bool_cell)
    return df


def _load_engine_output_snapshot() -> pd.DataFrame:
    """Fast last-good ABC engine result written by warm_engine.py."""
    try:
        if not _ENGINE_OUTPUT_PATH.exists():
            return pd.DataFrame()
        df = pd.read_csv(_ENGINE_OUTPUT_PATH, low_memory=False)
        return _normalise_engine_snapshot(df)
    except Exception:  # noqa: BLE001
        return pd.DataFrame()


def _sku_bin_view(df: pd.DataFrame) -> pd.DataFrame:
    """Return SKU -> Bin using only CIN7's Stock locator field."""
    if df is None or df.empty or "SKU" not in df.columns:
        return pd.DataFrame(columns=["SKU", "StockLocator", "Bin"])
    bin_cols = [c for c in _STOCK_LOCATOR_COLUMNS if c in df.columns]
    if not bin_cols:
        return pd.DataFrame(columns=["SKU", "StockLocator", "Bin"])

    def _first_non_empty_locator(row) -> str:
        for col in bin_cols:
            val = row.get(col)
            if val is None or pd.isna(val):
                continue
            text = str(val).strip()
            if text and text.lower() not in {"nan", "none", "null"}:
                return text
        return ""

    view = df[["SKU", *bin_cols]].copy()
    view["SKU"] = view["SKU"].astype(str)
    view["StockLocator"] = view.apply(_first_non_empty_locator, axis=1)
    view = view[view["StockLocator"] != ""]
    view["Bin"] = view["StockLocator"]
    return view[["SKU", "StockLocator", "Bin"]].drop_duplicates(
        subset=["SKU"])


def _stock_bin_view(stock_df: pd.DataFrame,
                    products_df: Optional[pd.DataFrame] = None
                    ) -> pd.DataFrame:
    """Return SKU -> Bin from stock data, falling back to products."""
    stock_view = _sku_bin_view(stock_df)
    product_view = _sku_bin_view(products_df)
    if stock_view.empty:
        return product_view
    if product_view.empty:
        return stock_view
    return pd.concat([stock_view, product_view], ignore_index=True
                     ).drop_duplicates(subset=["SKU"], keep="first")


def _engine_refresh_running(max_age_minutes: int = 45) -> bool:
    try:
        if not _ENGINE_REFRESH_LOCK.exists():
            return False
        age_min = (
            datetime.now().timestamp()
            - _ENGINE_REFRESH_LOCK.stat().st_mtime
        ) / 60.0
        return age_min <= max_age_minutes
    except OSError:
        return False


def _read_engine_refresh_status() -> dict:
    try:
        if not _ENGINE_REFRESH_STATUS.exists():
            return {}
        return json.loads(
            _ENGINE_REFRESH_STATUS.read_text(encoding="utf-8") or "{}")
    except Exception:  # noqa: BLE001
        return {}


def _format_engine_age(dt: datetime) -> str:
    age_min = (datetime.now() - dt).total_seconds() / 60.0
    if age_min < 1:
        return "just now"
    if age_min < 60:
        return f"{age_min:.0f} min ago"
    return f"{age_min/60:.1f} h ago"


def _write_engine_refresh_status(payload: dict) -> None:
    try:
        payload = dict(payload)
        payload["updated_at"] = datetime.utcnow().isoformat() + "Z"
        tmp = _ENGINE_REFRESH_STATUS.with_suffix(".tmp")
        tmp.write_text(json.dumps(payload, default=str), encoding="utf-8")
        tmp.replace(_ENGINE_REFRESH_STATUS)
    except Exception:  # noqa: BLE001
        pass


def _start_background_engine_refresh(reason: str,
                                     source_fp: Optional[tuple] = None
                                     ) -> bool:
    """Start warm_engine.py without blocking the current Streamlit user."""
    if os.environ.get("WARM_ENGINE_RUNNING") == "1":
        return False
    if _engine_refresh_running():
        return False
    try:
        OUTPUT_DIR.mkdir(parents=True, exist_ok=True)
        _ENGINE_REFRESH_LOCK.write_text(
            json.dumps({
                "started_at": datetime.utcnow().isoformat() + "Z",
                "reason": reason,
                "source_latest_mtime": (
                    _fingerprint_latest_mtime(source_fp)
                    if source_fp is not None else None),
            }, default=str),
            encoding="utf-8",
        )
        _write_engine_refresh_status({
            "state": "running",
            "reason": reason,
        })
        env = os.environ.copy()
        env.setdefault("DATA_DIR", str(OUTPUT_DIR.parent))
        env.setdefault("STREAMLIT_HOME", str(OUTPUT_DIR.parent / ".streamlit"))
        env["WARM_ENGINE_RUNNING"] = "1"
        env["ENGINE_REFRESH_LOCK_PATH"] = str(_ENGINE_REFRESH_LOCK)
        env["ENGINE_REFRESH_STATUS_PATH"] = str(_ENGINE_REFRESH_STATUS)
        env["ENGINE_REFRESH_REASON"] = reason
        log_fh = _ENGINE_REFRESH_LOG.open("a", encoding="utf-8")
        subprocess.Popen(
            [sys.executable, "warm_engine.py"],
            cwd=str(APP_DIR),
            stdout=log_fh,
            stderr=subprocess.STDOUT,
            stdin=subprocess.DEVNULL,
            close_fds=True,
            env=env,
        )
        log_fh.close()
        return True
    except Exception as exc:  # noqa: BLE001
        try:
            _ENGINE_REFRESH_LOCK.unlink(missing_ok=True)
        except Exception:
            pass
        _write_engine_refresh_status({
            "state": "failed_to_start",
            "reason": reason,
            "error": repr(exc),
        })
        return False


# Empty-frame factories used by loaders when no CSVs exist on disk yet.
# Why: many call sites do `df["Foo"]` without first checking the column
# exists. Rather than guarding every site, we make the loaders return a
# DataFrame with the EXPECTED columns even when there are zero rows.
# A consumer doing `df["InvoiceDate"]` then gets an empty Series instead
# of a KeyError. Keeps the deploy bring-up much smoother.
_EMPTY_SALE_LINES_COLS = [
    "SaleID", "OrderNumber", "InvoiceNumber", "InvoiceDate", "OrderDate",
    "Customer", "CustomerID", "SKU", "ProductID", "Name", "Quantity",
    "Price", "Discount", "Tax", "Total", "AverageCost", "Status",
    "SourceChannel", "SalesRepresentative", "CustomerReference",
    "ShippingNotes", "Terms", "Memo", "Note", "SaleType", "UOM"]
_EMPTY_SALES_COLS = [
    "SaleID", "OrderNumber", "InvoiceNumber", "InvoiceDate", "OrderDate",
    "Customer", "CustomerID", "Status", "Total", "InvoiceAmount",
    "GrandTotal", "Tax", "CustomerReference", "SourceChannel",
    "SalesRepresentative", "SaleType", "ShippingNotes", "Terms",
    "Memo", "Note", "CombinedShippingStatus", "FulFilmentStatus"]
_EMPTY_PURCHASE_LINES_COLS = [
    "PurchaseID", "OrderNumber", "OrderDate", "RequiredBy", "Supplier",
    "SupplierID", "Status", "SKU", "ProductID", "Name", "Quantity",
    "Price", "Discount", "Tax", "Total", "UOM", "Comments",
    "ShippingNotes", "AttributeNotes", "Memo", "Note", "Terms"]

_SALE_LINES_USECOLS = _EMPTY_SALE_LINES_COLS + [
    "Location", "LocationID", "InvoiceAmount"]
_SALE_LINES_NUMERIC_COLS = (
    "Quantity", "Price", "Discount", "Tax", "Total", "AverageCost",
    "InvoiceAmount")
_SALES_HEADERS_USECOLS = _EMPTY_SALES_COLS + [
    "Type", "FulfillmentStatus", "ShipBy", "RequiredBy"]
_SALES_HEADERS_NUMERIC_COLS = (
    "Total", "InvoiceAmount", "GrandTotal", "Tax")
_PURCHASE_LINES_USECOLS = _EMPTY_PURCHASE_LINES_COLS + [
    "AverageCost", "InvoiceDate", "InvoiceNumber", "SupplierSKU",
    "Supplier SKU", "Currency", "BaseCurrency", "SupplierCurrency",
    "ShipDate", "TrackingNumber", "ShippingMethod", "DeliveryDate",
    "ExpectedDate", "Location", "LocationID", "QuantityReceived",
    "ReceivedQuantity", "ReceivedAgainstOrder", "QuantityRemaining"]
_PURCHASE_LINES_NUMERIC_COLS = (
    "Quantity", "Price", "Discount", "Tax", "Total", "AverageCost",
    "QuantityReceived", "ReceivedQuantity", "ReceivedAgainstOrder",
    "QuantityRemaining")


# Load the most comprehensive sale_lines picture:
# 1. Start with the longest-window file (has deepest history)
# 2. Union any more-recent shorter-window files (they contain today's data
#    that the overnight long-window sync missed)
# 3. Dedupe on line identity (SaleID+SKU+Qty), keeping the most-recent version
@st.cache_data(persist="disk", show_spinner="Loading sales history…")
def _load_longest_sale_lines_cached(fingerprint: tuple) -> pd.DataFrame:
    import re as _re
    files = []
    for p in OUTPUT_DIR.glob("sale_lines_last_*d_*.csv"):
        m = _re.match(r"sale_lines_last_(\d+)d_", p.name)
        if m:
            files.append((int(m.group(1)), p.stat().st_mtime, p))
    if not files:
        # Return an empty frame WITH expected columns so downstream
        # df["InvoiceDate"] etc. doesn't KeyError on a fresh deploy.
        return pd.DataFrame(columns=_EMPTY_SALE_LINES_COLS)

    # Largest-window file first, then any more-recent smaller files
    files.sort(key=lambda x: (-x[0], -x[1]))
    base_file = files[0][2]
    base_mtime = files[0][1]
    base = _read_csv_lean(base_file, _SALE_LINES_USECOLS,
                          _SALE_LINES_NUMERIC_COLS)
    if len(base.columns) == 0:
        return pd.DataFrame(columns=_EMPTY_SALE_LINES_COLS)

    # Union any file that was written MORE RECENTLY than the base
    for days, mtime, p in files[1:]:
        if mtime <= base_mtime:
            continue
        more = _read_csv_lean(p, _SALE_LINES_USECOLS,
                              _SALE_LINES_NUMERIC_COLS)
        if more.empty:
            continue
        base = pd.concat([base, more], ignore_index=True)

    # Dedupe keeping LAST occurrence (the more-recent file's data).
    #
    # v2.67.328 — dedupe on InvoiceNumber, NOT InvoiceDate. James
    # 2026-05-28: LED-NEON-FLEX-SUPER-SLIM-ST showed its single 12-unit
    # sale in TWO adjacent months ("…0 12 12"). Cause: the same invoice
    # line gets re-synced with a changed InvoiceDate (CIN7 re-invoicing,
    # or a date-format / timezone shift between the multi-window files
    # we union here). With InvoiceDate in the key the two records differ
    # only by date, so drop_duplicates keeps BOTH → the units land in
    # two monthly buckets and every demand figure double-counts.
    # An invoice has exactly ONE date, so two rows sharing
    # SaleID+SKU+Quantity+InvoiceNumber+OrderNumber but differing only
    # by InvoiceDate are definitionally the same line — collapsing them
    # is strictly correct. Genuinely separate invoices (different
    # InvoiceNumber, e.g. partial/advanced-sale invoicing) keep distinct
    # keys and survive.
    dedupe_cols = [c for c in
                    ["SaleID", "SKU", "Quantity", "InvoiceNumber",
                     "OrderNumber"]
                    if c in base.columns]
    if dedupe_cols:
        base = base.drop_duplicates(subset=dedupe_cols, keep="last")

    # v2.67.331 — second-pass dedup for the revision/void case that
    # the v2.67.330 Status filter can't reliably catch (CIN7 doesn't
    # always surface "Status": "VOIDED" on the per-invoice element).
    # If the SAME (SaleID, SKU, Quantity, OrderNumber) line survived
    # under MULTIPLE InvoiceNumbers, it's almost always a revision
    # CIN7 kept in the Invoices array — keep only the LATEST by
    # InvoiceDate. James 2026-05-28→06-01: LED-NEON-FLEX-SUPER-SLIM-ST
    # showed "0 0 0 0 12 12" through three engine versions because the
    # two records have distinct invoice numbers and the Status field
    # didn't help.
    #
    # Safe because the first pass above already collapsed the only
    # legitimate same-invoice multi-line case (two lines of same
    # SKU+Qty on ONE invoice → same InvoiceNumber → already deduped).
    # The remaining cross-invoice duplication is overwhelmingly the
    # revision artifact. Acknowledged trade-off: a real partial
    # shipment with two EQUAL-quantity halves on different invoices
    # would collapse to one — that pattern is rare and obvious to a
    # buyer eyeballing the data.
    second_key = [c for c in
                   ["SaleID", "SKU", "Quantity", "OrderNumber"]
                   if c in base.columns]
    if second_key and "InvoiceDate" in base.columns:
        # NaT (no invoice yet) sorts to the start, so order lines lose
        # to actual invoice rows for the same sale → correct.
        base = base.sort_values(
            "InvoiceDate", na_position="first", kind="stable")
        base = base.drop_duplicates(subset=second_key, keep="last")
    base = _ensure_columns(base, _EMPTY_SALE_LINES_COLS)
    return base.reset_index(drop=True)


def _load_longest_sale_lines() -> pd.DataFrame:
    return _load_longest_sale_lines_cached(
        _dir_fingerprint("sale_lines_last_*d_*.csv"))


sale_lines = _load_longest_sale_lines()
if sale_lines.empty:
    sale_lines = sale_lines_30d if not sale_lines_30d.empty else sale_lines_3d


# v2.67.334 — assembly (FG-XXXX) consumption loader. Same union+dedup
# pattern as sale_lines. Each row is one component pick-line consumed
# by an assembly task: (TaskID, AssemblyNumber, Date, CompletionDate,
# Status, ParentSKU, ComponentSKU, Quantity, ...). This is GROUND TRUTH
# for components whose demand is mostly being-built-into-kits — the BOM
# rollup is derived and usually incomplete. James 2026-06-01 example:
# LED-NEON-FLEX-NICHO-3000K-2 had ~90 FG- consumptions vs ~5 direct
# sales per month; the engine was seeing ~half of true demand.
@st.cache_data(ttl=900, show_spinner=False)
def _load_longest_assemblies_cached(fingerprint: tuple) -> pd.DataFrame:
    import re as _re
    files = []
    for p in OUTPUT_DIR.glob("assemblies_last_*d_*.csv"):
        m = _re.match(r"assemblies_last_(\d+)d_", p.name)
        if m:
            files.append((int(m.group(1)), p.stat().st_mtime, p))
    if not files:
        return pd.DataFrame(columns=[
            "TaskID", "AssemblyNumber", "Date", "CompletionDate",
            "Status", "ParentProductID", "ParentSKU", "ParentName",
            "ParentQuantity", "ComponentProductID", "ComponentSKU",
            "ComponentName", "Quantity", "Unit", "Cost", "BinID", "Bin",
        ])
    # Largest window first, then more-recent smaller files unioned
    files.sort(key=lambda x: (-x[0], -x[1]))
    base_file = files[0][2]
    base_mtime = files[0][1]
    try:
        base = pd.read_csv(base_file, low_memory=False)
    except Exception:
        return pd.DataFrame()
    for days, mtime, p in files[1:]:
        if mtime <= base_mtime:
            continue
        try:
            more = pd.read_csv(p, low_memory=False)
            base = pd.concat([base, more], ignore_index=True)
        except Exception:
            continue
    # Dedupe on (TaskID, ComponentSKU, Quantity, BinID) — covers the case
    # where the same task appears in two windows AND the rare same-task
    # multi-bin pick of one SKU. Keep the most recent file's row.
    dedupe_cols = [c for c in
                    ["TaskID", "ComponentSKU", "Quantity", "BinID"]
                    if c in base.columns]
    if dedupe_cols:
        base = base.drop_duplicates(subset=dedupe_cols, keep="last")
    return base.reset_index(drop=True)


def _load_longest_assemblies() -> pd.DataFrame:
    return _load_longest_assemblies_cached(
        _dir_fingerprint("assemblies_last_*d_*.csv"))


assemblies = _load_longest_assemblies()

# sales_full (order-level headers) is loaded LATER, after its
# loader function is defined further down the file. See the line
# `sales_full = _load_longest_sales()` after the purchase-lines
