@st.cache_data(persist="disk", show_spinner="Loading sales headers…")
def _load_longest_sales_cached(fingerprint: tuple) -> pd.DataFrame:
    """Headers version. fingerprint key: see _dir_fingerprint()."""
    import re as _re
    files = []
    for p in OUTPUT_DIR.glob("sales_last_*d_*.csv"):
        m = _re.match(r"sales_last_(\d+)d_", p.name)
        if m:
            files.append((int(m.group(1)), p.stat().st_mtime, p))
    if not files:
        return pd.DataFrame(columns=_EMPTY_SALES_COLS)
    files.sort(key=lambda x: (-x[0], -x[1]))
    base_file = files[0][2]
    base_mtime = files[0][1]
    base = _read_csv_lean(base_file, _SALES_HEADERS_USECOLS,
                          _SALES_HEADERS_NUMERIC_COLS)
    if len(base.columns) == 0:
        return pd.DataFrame(columns=_EMPTY_SALES_COLS)
    for days, mtime, p in files[1:]:
        if mtime <= base_mtime:
            continue
        more = _read_csv_lean(p, _SALES_HEADERS_USECOLS,
                              _SALES_HEADERS_NUMERIC_COLS)
        if more.empty:
            continue
        base = pd.concat([base, more], ignore_index=True)
    if "SaleID" in base.columns:
        base = base.drop_duplicates(subset=["SaleID"], keep="last")
    base = _ensure_columns(base, _EMPTY_SALES_COLS)
    return base.reset_index(drop=True)


def _load_longest_sales() -> pd.DataFrame:
    return _load_longest_sales_cached(
        _dir_fingerprint("sales_last_*d_*.csv"))


@st.cache_data(persist="disk", show_spinner="Loading purchase history…")
def _load_longest_purchase_lines_cached(fingerprint: tuple) -> pd.DataFrame:
    import re as _re
    files = []
    for p in OUTPUT_DIR.glob("purchase_lines_last_*d_*.csv"):
        m = _re.match(r"purchase_lines_last_(\d+)d_", p.name)
        if m:
            files.append((int(m.group(1)), p.stat().st_mtime, p))
    if not files:
        return pd.DataFrame(columns=_EMPTY_PURCHASE_LINES_COLS)
    files.sort(key=lambda x: (-x[0], -x[1]))
    base_file = files[0][2]
    base_mtime = files[0][1]
    base = _read_csv_lean(base_file, _PURCHASE_LINES_USECOLS,
                          _PURCHASE_LINES_NUMERIC_COLS)
    if len(base.columns) == 0:
        return pd.DataFrame(columns=_EMPTY_PURCHASE_LINES_COLS)
    for days, mtime, p in files[1:]:
        if mtime <= base_mtime:
            continue
        more = _read_csv_lean(p, _PURCHASE_LINES_USECOLS,
                              _PURCHASE_LINES_NUMERIC_COLS)
        if more.empty:
            continue
        # v2.67.275 — PO-level replacement: if the newer file has a
        # fresher sync for a PurchaseID, drop ALL rows for that ID from
        # the older file before merging. Without this, a PO that was
        # synced in ORDERING state (in the 90d file) and then invoiced
        # (captured in the 30d file with new prices/qty) would produce
        # duplicate SKU rows — one ORDERING and one INVOICED per SKU —
        # because the old dedup key included Price, which changed.
        if "PurchaseID" in base.columns and "PurchaseID" in more.columns:
            newer_pids = set(more["PurchaseID"].dropna().unique())
            base = base[~base["PurchaseID"].isin(newer_pids)]
        base = pd.concat([base, more], ignore_index=True)
    # Final row-level dedup: catches any remaining duplicates within
    # a single file (e.g. checkpoint replay edge cases).
    dedupe_cols = [c for c in
                    ["PurchaseID", "SKU", "Quantity", "OrderDate",
                     "OrderNumber", "Price"]
                    if c in base.columns]
    if dedupe_cols:
        base = base.drop_duplicates(subset=dedupe_cols, keep="last")
    base = _ensure_columns(base, _EMPTY_PURCHASE_LINES_COLS)
    return base.reset_index(drop=True)


def _load_longest_purchase_lines() -> pd.DataFrame:
    return _load_longest_purchase_lines_cached(
        _dir_fingerprint("purchase_lines_last_*d_*.csv"))


# v2.67.54 — ShipStation shipments loader. Same merge pattern as
# the purchase / sale loaders: full backfill (`shipments_full.csv`)
# acts as the base, rolling-window files (`shipments_last_<N>d_*.csv`)
# layer newer rows on top. ShipmentID is the dedup key — every
# shipment has a unique ID and re-sync of the same shipment gives
# the same ID back, so 'last update wins' produces the right
# row. The cache invalidates whenever any file in the pattern
# changes, mirroring `_dir_fingerprint` for the others.
# v2.67.85 — memory-conscious shipments loader. With the 5-year
# backfill (43,984 shipments × ~50 cols), the previous full-load
# was pushing the 2GB Render instance over its limit and OOMing
# during page render (Monthly Metrics showed $0 for every month
# despite the data being on disk). Fixes:
#   1. Read only the columns we actually use across the codebase
#      (drops ~28 unused columns × 44k rows = ~150MB savings).
#   2. Cast numerics to float32 / int32 — float64 is overkill for
#      shipping costs and dimensions.
#   3. Drop voided shipments at load time — they're filtered out
#      by every consumer anyway, so why hold them in RAM.
_SHIPMENTS_USECOLS = [
    # Identity
    "ShipmentID", "OrderID", "OrderNumber",
    # Dates / status
    "ShipDate", "CreateDate", "VoidDate", "Voided", "ShipmentStatus",
    # Cost / margin (the v2.67.55c-and-later columns)
    "ShipmentCost", "CustomerShippingCharge", "ShippingMargin",
    "AmountPaid", "TaxPaid", "Currency", "InsuranceCost",
    # Carrier / tracking (consumed by AI's get_shipping_details)
    "TrackingNumber", "TrackingURL", "TrackingStatus",
    "CarrierCode", "ServiceCode",
    # Recipient / address (AI tool needs these)
    "CustomerEmail", "CustomerName", "ShipToCity", "ShipToState",
    "ShipToPostal", "ShipToCountry", "ShipToCompany",
    # Package metrics (DIM-weight + label-cost analysis)
    "WeightValue", "WeightUnits", "Zone",
    "DimensionsLength", "DimensionsWidth", "DimensionsHeight",
    "DimensionsUnits", "ItemCount", "ItemSummary",
    "LabelID",
]
_SHIPMENTS_DTYPE = {
    # v2.67.86 — only float32 hints retained. Earlier Int8/Int16
    # casts silently failed on rare non-numeric Zone/ItemCount
    # values, dropping the whole file load. category dtypes also
    # removed for now to be conservative; we can re-add them once
    # we confirm a clean baseline.
    "ShipmentCost": "float32",
    "CustomerShippingCharge": "float32",
    "ShippingMargin": "float32",
    "AmountPaid": "float32",
    "TaxPaid": "float32",
    "InsuranceCost": "float32",
    "WeightValue": "float32",
    "DimensionsLength": "float32",
    "DimensionsWidth": "float32",
    "DimensionsHeight": "float32",
}


@st.cache_data(persist="disk",
                show_spinner="Loading shipping history…")
def _load_longest_shipments_cached(fingerprint: tuple) -> pd.DataFrame:
    files = []
    full_path = OUTPUT_DIR / "shipments_full.csv"
    if full_path.exists():
        files.append(("full", full_path.stat().st_mtime, full_path))
    import re as _re
    for p in OUTPUT_DIR.glob("shipments_last_*d_*.csv"):
        m = _re.match(r"shipments_last_(\d+)d_", p.name)
        if m:
            files.append((int(m.group(1)), p.stat().st_mtime, p))
    if not files:
        # Empty schema so consumers don't crash on column access.
        return pd.DataFrame(columns=[
            "ShipmentID", "OrderNumber", "ShipDate", "ShipmentCost",
            "TrackingNumber", "CarrierCode", "ServiceCode",
            "CustomerName", "Voided"])
    # Sort: 'full' (the backfill) first as base; then by descending
    # window width; then by descending mtime. Each subsequent file
    # is concat'd on top.
    def _sort_key(item):
        days, mtime, _p = item
        if days == "full":
            return (-10**9, -mtime)
        return (-days, -mtime)
    files.sort(key=_sort_key)
    base = pd.DataFrame()
    base_mtime = 0.0

    # Build a usecols filter that's tolerant of older CSVs missing
    # some columns. pandas' usecols= raises on missing names, so we
    # peek at the header first per-file.
    # v2.67.86 — robust dtype handling. v2.67.85's eager dtype hints
    # could silently fail on edge cases (e.g. Int8 cast on a Zone
    # column containing rare non-numeric values) → _read_lean
    # returned None → loader returned empty DataFrame → all months
    # showed $0. New approach: try with dtype hints; on failure,
    # fall back to no-dtype load (safe but uses more RAM); on second
    # failure, log and skip.
    import sys as _sys

    def _read_lean(p):
        try:
            header = pd.read_csv(p, nrows=0).columns.tolist()
        except Exception as exc:
            print(f"[shipments] header read failed for {p.name}: {exc}",
                    file=_sys.stderr)
            return None
        cols = [c for c in _SHIPMENTS_USECOLS if c in header]
        dtypes = {k: v for k, v in _SHIPMENTS_DTYPE.items()
                    if k in cols}
        df = None
        try:
            df = pd.read_csv(p, usecols=cols, dtype=dtypes,
                                low_memory=False)
        except Exception as exc:
            print(f"[shipments] dtype load failed for {p.name}: "
                    f"{exc}; falling back to no-dtype",
                    file=_sys.stderr)
            try:
                df = pd.read_csv(p, usecols=cols, low_memory=False)
            except Exception as exc2:
                print(f"[shipments] usecols load also failed: {exc2}",
                        file=_sys.stderr)
                return None
        if df is None or df.empty:
            return None
        # Drop voided rows at load time — every consumer filters
        # them out anyway; no point holding them in RAM.
        if "Voided" in df.columns:
            v = df["Voided"]
            if v.dtype == "bool":
                vb = v.fillna(False)
            else:
                vb = (v.astype(str).str.strip().str.lower()
                        .isin(["true", "1", "yes", "t"]))
            df = df[~vb]
        return df

    for _days, mtime, p in files:
        chunk = _read_lean(p)
        if chunk is None:
            continue
        if base.empty:
            base = chunk
            base_mtime = mtime
            continue
        # Only merge in newer files (older snapshots would just
        # reintroduce stale rows the dedup might keep).
        if mtime <= base_mtime:
            continue
        base = pd.concat([base, chunk], ignore_index=True)
    if "ShipmentID" in base.columns:
        base = base.drop_duplicates(subset=["ShipmentID"], keep="last")
    return base.reset_index(drop=True)


def _load_longest_shipments() -> pd.DataFrame:
    # v2.67.87 — explicit cache-buster appended to the fingerprint.
    # Streamlit's persist="disk" can hold stale results across
    # function-body changes when underlying file mtimes haven't
    # also changed. Bump CACHE_BUSTER on any code change that
    # affects the loader output to guarantee re-computation.
    CACHE_BUSTER = "v88"  # v2.67.88: bumped to force re-load
    fp = _dir_fingerprint("shipments_*.csv")
    return _load_longest_shipments_cached((fp, CACHE_BUSTER))


